// Query customers whose birthday is today
// This is a template - replace with actual database/API query

const today = new Date();
const currentMonth = today.getMonth() + 1;
const currentDay = today.getDate();

// Sample customer data - replace with your actual data source
const customers = [
  { id: 1, name: 'John Doe', email: 'john@example.com', birthDate: '1990-03-15', phone: '+1234567890' },
  { id: 2, name: 'Jane Smith', email: 'jane@example.com', birthDate: '1985-03-15', phone: '+0987654321' },
  // ... more customers
];

// Filter customers with birthday today
const birthdayCustomers = customers.filter(customer => {
  const birthDate = new Date(customer.birthDate);
  return (birthDate.getMonth() + 1) === currentMonth && birthDate.getDate() === currentDay;
});

return birthdayCustomers.map(customer => ({
  json: customer
}));

// Generate personalized birthday offer for each customer

items.forEach(item => {
  const customer = item.json;
  const firstName = customer.name.split(' ')[0];

  // Generate unique coupon code
  const couponCode = 'BDAY' + customer.id.toString().padStart(4, '0') + 
    Math.random().toString(36).substring(2, 6).toUpperCase();

  // Offer details
  item.json.offer = {
    couponCode: couponCode,
    discountPercentage: 25,
    validUntil: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0], // 7 days
    minimumPurchase: 50,
    freeGift: 'Birthday Surprise Gift'
  };

  // Personalize message
  item.json.personalizedMessage = `Happy Birthday ${firstName}! Enjoy ${item.json.offer.discountPercentage}% off and a free ${item.json.offer.freeGift} with your next purchase. Use code: ${couponCode}`;

  // Email content
  item.json.emailContent = {
    subject: `🎂 Happy Birthday ${firstName}! Your Special Gift Inside`,    
    body: `<h1>Happy Birthday ${firstName}! 🎉</h1>
           <p>To celebrate your special day, we're giving you:</p>
           <ul>
             <li><strong>${item.json.offer.discountPercentage}% OFF</strong> your next purchase</li>
             <li><strong>Free ${item.json.offer.freeGift}</strong> with orders over $${item.json.offer.minimumPurchase}</li>
           </ul>
           <p>Use code: <strong>${item.json.offer.couponCode}</strong></p>
           <p>Valid until: ${item.json.offer.validUntil}</p>
           <p>🎁 <a href="https://yourstore.com/birthday-offer">Claim Your Birthday Offer</a></p>
           <p>With love,<br>Your Store Team</p>`
  };

  // SMS content
  item.json.smsContent = `Happy Bday ${firstName}! ${item.json.offer.discountPercentage}% off + free gift on us! Code: ${couponCode}. Valid 7 days. Shop now: yourstore.com/bday`;
});

return items;

// Log successful birthday offers
const timestamp = new Date().toISOString();

items.forEach(item => {
  console.log(`Birthday offer sent to ${item.json.name} (${item.json.email}) at ${timestamp}`);
  console.log(`Coupon: ${item.json.offer.couponCode}`);
});

// Store in Google Sheets for tracking
const offersSent = items.map(item => ({
  date: timestamp,
  customerName: item.json.name,
  customerEmail: item.json.email,
  couponCode: item.json.offer.couponCode,
  discount: item.json.offer.discountPercentage,
  expiry: item.json.offer.validUntil
}));

// Add to items for next node
items.push({ json: { log: offersSent } });

return items;

